    var status any = this.SafeString(raw, "status")
    var active any = ccxt.IsTrue((ccxt.IsEqual(status, "active"))) || ccxt.IsTrue((ccxt.IsEqual(status, "open")))
    var endDate any = this.SafeString(raw, "expiration_time")
