/**
 * @ignore
 * @method
 * @name kalshi#parseOrder
 * @description parses a raw kalshi order object into a unified order object
 * @param {object} order the raw order object
 * @param {object} [market] the outcome object the order belongs to
 * @returns {object} an [order structure](https://docs.ccxt.com/#/?id=order-structure)
 */
func  (this *KalshiCore) ParseOrder(order any, optionalArgs ...any) any  {
    market := ccxt.GetArg(optionalArgs, 0, nil)
    _ = market
    var id any = this.SafeString(order, "order_id")
    var ticker any = this.SafeString(order, "ticker")
    var mkt any = this.SafeOutcome(ticker, market)
    var status any = this.ParseOrderStatus(this.SafeString(order, "status"))
    var action any = this.SafeString(order, "action")
    var side any = ccxt.Ternary(ccxt.IsTrue((ccxt.IsEqual(action, "buy"))), "buy", "sell")
    // price in the outcome's own leg: V2 returns *_price_dollars (already dollars),
    // legacy returned yes_price/no_price in cents
    var labelIsNo any =     (ccxt.IsEqual(this.SafeStringUpper(mkt, "label"), "NO"))
    var dollarsKey any = ccxt.Ternary(ccxt.IsTrue((labelIsNo)), "no_price_dollars", "yes_price_dollars")
    var centsKey any = ccxt.Ternary(ccxt.IsTrue((labelIsNo)), "no_price", "yes_price")
    var price any = this.SafeNumber(order, dollarsKey)
    if ccxt.IsTrue(ccxt.IsEqual(price, nil)) {
        var priceCents any = this.SafeNumber(order, centsKey)
        if ccxt.IsTrue(!ccxt.IsEqual(priceCents, nil)) {
            price = ccxt.Divide(priceCents, 100)
        }
    }
    // V2 counts are fixed-point (*_count_fp); legacy used count / filled_count
    var amount any = this.SafeNumber2(order, "initial_count_fp", "count")
    var filled any = this.SafeNumber2(order, "fill_count_fp", "filled_count", 0)
    var remaining any = this.SafeNumber(order, "remaining_count_fp")
    if ccxt.IsTrue(ccxt.IsTrue(ccxt.IsTrue((ccxt.IsEqual(remaining, nil))) && ccxt.IsTrue((!ccxt.IsEqual(amount, nil)))) && ccxt.IsTrue((!ccxt.IsEqual(filled, nil)))) {
        remaining = ccxt.Subtract(amount, filled)
    }
    var ts any = this.Parse8601(this.SafeString(order, "created_time"))
    return this.SafePredictionOrder(map[string]any {
        "id": id,
        "clientOrderId": this.SafeString(order, "client_order_id"),
        "info": order,
        "timestamp": ts,
        "datetime": this.Iso8601(ts),
        "lastTradeTimestamp": nil,
        "status": status,
        "outcome": this.SafeString(mkt, "outcome"),
        "outcomeId": this.SafeString2(mkt, "outcomeId", "id"),
        "label": this.SafeString(mkt, "label"),
        "market": this.SafeString2(mkt, "market", "outcome"),
        "type": this.SafeStringLower(order, "type", "limit"),
        "timeInForce": "GTC",
        "postOnly": nil,
        "side": side,
        "price": price,
        "stopPrice": nil,
        "triggerPrice": nil,
        "average": nil,
        "amount": amount,
        "cost": nil,
        "filled": filled,
        "remaining": remaining,
        "fee": nil,
        "trades": []any{},
    }, mkt)
}
/**
 * @ignore
 * @method
 * @name kalshi#parseOrderStatus
 * @description maps a kalshi order status string to the CCXT unified status vocabulary
 * @param {string} status the raw kalshi order status
 * @returns {string} the unified order status
 */
func  (this *KalshiCore) ParseOrderStatus(status any) any  {
    var statuses any = map[string]any {
        "resting": "open",
        "executed": "closed",
        "canceled": "canceled",
        "pending": "open",
    }
    return this.SafeString(statuses, status, status)
}
/**
 * @method
 * @name kalshi#createOrder
 * @description places a limit or market order on kalshi for the given outcome token
 * @see https://trading-api.readme.io/reference/createorder
 * @param {string} outcome unified outcome
 * @param {string} type 'limit' or 'market'
 * @param {string} side 'buy' or 'sell'
 * @param {float} amount number of contracts
 * @param {float} [price] limit price in dollars (0–1 range)
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {object} an [order structure](https://docs.ccxt.com/#/?id=order-structure)
 */
func  (this *KalshiCore) CreateOrder(outcome any, typeVar any, side any, amount any, optionalArgs ...any) <- chan any {
            ch := make(chan any)
            go func() any {
                defer close(ch)
                defer ccxt.ReturnPanicError(ch)
                    price := ccxt.GetArg(optionalArgs, 0, nil)
            _ = price
            params := ccxt.GetArg(optionalArgs, 1, map[string]any {})
            _ = params
            this.CheckEvents(outcome)
            var outcomeObj any = this.Outcome(outcome)
            var ticker any = this.SafeString(ccxt.GetValue(outcomeObj, "info"), "ticker")
            var isNo any =     (ccxt.IsEqual(ccxt.GetValue(outcomeObj, "label"), "NO"))
            var isBuy any =     (ccxt.IsEqual(side, "buy"))
            // kalshi V2 (/portfolio/events/orders) quotes the YES leg only: side 'bid' = buy YES,
            // 'ask' = sell YES, price in dollars. a NO order maps to the complementary YES order
            // (buy NO @ q == sell YES @ 1-q), so flip the book side and the price
            var bookSide any = ccxt.Ternary(ccxt.IsTrue((isBuy)), "bid", "ask")
            var yesPrice any = price
            if ccxt.IsTrue(isNo) {
                bookSide = ccxt.Ternary(ccxt.IsTrue((isBuy)), "ask", "bid")
                if ccxt.IsTrue(!ccxt.IsEqual(price, nil)) {
                    yesPrice = this.ParseNumber(ccxt.Precise.StringSub("1", this.NumberToString(price)))
                }
            }
            var isMarket any =     (ccxt.IsEqual(typeVar, "market"))
            var defaultTif any = ccxt.Ternary(ccxt.IsTrue((isMarket)), "immediate_or_cancel", "good_till_canceled")
            var timeInForce any = nil
            timeInForceparamsVariable := this.HandleOptionAndParams(params, "createOrder", "time_in_force", defaultTif)
            timeInForce = ccxt.GetValue(timeInForceparamsVariable,0)
            params = ccxt.GetValue(timeInForceparamsVariable,1)
            var stp any = nil
            stpparamsVariable := this.HandleOptionAndParams(params, "createOrder", "self_trade_prevention_type", "taker_at_cross")
            stp = ccxt.GetValue(stpparamsVariable,0)
            params = ccxt.GetValue(stpparamsVariable,1)
            var request any = map[string]any {
                "ticker": ticker,
                "side": bookSide,
                "count": this.NumberToString(amount),
                "time_in_force": timeInForce,
                "self_trade_prevention_type": stp,
            }
            if ccxt.IsTrue(!ccxt.IsEqual(yesPrice, nil)) {
                ccxt.AddElementToObject(request, "price", this.NumberToString(yesPrice))
            }
        
            response:= (<-this.KalshiPrivatePostPortfolioEventsOrders(this.Extend(request, params)))
            ccxt.PanicOnError(response)
            // the V2 create response is minimal (order_id, fill_count, remaining_count), so backfill
            // the known order details and resolve the status from the remaining count
            var order any = this.ParseOrder(response, outcomeObj)
            ccxt.AddElementToObject(order, "side", side)
            ccxt.AddElementToObject(order, "amount", amount)
            ccxt.AddElementToObject(order, "price", price)
            if ccxt.IsTrue(ccxt.IsEqual(ccxt.GetValue(order, "status"), nil)) {
                var remaining any = this.SafeNumber(response, "remaining_count")
                var resolvedStatus any = "open"
                if ccxt.IsTrue(ccxt.IsTrue((!ccxt.IsEqual(remaining, nil))) && ccxt.IsTrue((ccxt.IsEqual(remaining, 0)))) {
                    resolvedStatus = "closed"
                }
                ccxt.AddElementToObject(order, "status", resolvedStatus)
            }
        
            ch <- order
            return nil
        
            }()
            return ch
        }
/**
 * @method
 * @name kalshi#cancelOrder
 * @description cancels a single open order by id on kalshi
 * @see https://trading-api.readme.io/reference/cancelorder
 * @param {string} id order id
 * @param {string} [outcome] unified outcome
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {object} an [order structure](https://docs.ccxt.com/#/?id=order-structure)
 */
func  (this *KalshiCore) CancelOrder(id any, optionalArgs ...any) <- chan any {
            ch := make(chan any)
            go func() any {
                defer close(ch)
                defer ccxt.ReturnPanicError(ch)
                    outcome := ccxt.GetArg(optionalArgs, 0, nil)
            _ = outcome
            params := ccxt.GetArg(optionalArgs, 1, map[string]any {})
            _ = params
            if ccxt.IsTrue(!ccxt.IsEqual(outcome, nil)) {
                this.CheckEvents(outcome)
            } else {
                this.CheckEvents()
            }
            // v2 cancel: DELETE /portfolio/events/orders/{order_id} (the /portfolio/orders/{id}
            // and /portfolio/orders/batched paths are deprecated v1 endpoints returning 410 Gone)
        
            response:= (<-this.KalshiPrivateDeletePortfolioEventsOrdersOrderId(this.Extend(map[string]any {
            "order_id": id,
        }, params)))
            ccxt.PanicOnError(response)
        
            ch <- this.ParseOrder(this.SafeDict(response, "order", response))
            return nil
        
            }()
            return ch
        }
/**
 * @method
 * @name kalshi#cancelAllOrders
 * @description cancels all open orders on kalshi, optionally scoped to one outcome ticker
 * @see https://trading-api.readme.io/reference/cancelorders
 * @param {string} [outcome] unified outcome to scope the cancellation to
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {object[]} a list of [order structures](https://docs.ccxt.com/#/?id=order-structure)
 */
func  (this *KalshiCore) CancelAllOrders(optionalArgs ...any) <- chan any {
            ch := make(chan any)
            go func() any {
                defer close(ch)
                defer ccxt.ReturnPanicError(ch)
                    outcome := ccxt.GetArg(optionalArgs, 0, nil)
            _ = outcome
            params := ccxt.GetArg(optionalArgs, 1, map[string]any {})
            _ = params
            if ccxt.IsTrue(!ccxt.IsEqual(outcome, nil)) {
                this.CheckEvents(outcome)
            } else {
                this.CheckEvents()
            }
            // kalshi has no "cancel all" / batch-cancel endpoint (the v1 DELETE /portfolio/orders
            // and /portfolio/orders/batched paths are 410 Gone) — fetch the resting orders and
            // cancel them one by one via the v2 DELETE /portfolio/events/orders/{order_id}
            var request any = map[string]any {
                "status": "resting",
            }
            if ccxt.IsTrue(!ccxt.IsEqual(outcome, nil)) {
                var outcomeObj any = this.Outcome(outcome)
                ccxt.AddElementToObject(request, "ticker", this.SafeString(ccxt.GetValue(outcomeObj, "info"), "ticker"))
            }
        
            restingResponse:= (<-this.KalshiPrivateGetPortfolioOrders(request))
            ccxt.PanicOnError(restingResponse)
            var restingOrders any = this.SafeList(restingResponse, "orders", []any{})
            var restingOrdersLength any =     ccxt.GetArrayLength(restingOrders)
            var canceledOrders any = []any{}
            for i := 0; ccxt.IsLessThan(i, restingOrdersLength); i++ {
                var orderId any = this.SafeString(ccxt.GetValue(restingOrders, i), "order_id")
                if ccxt.IsTrue(!ccxt.IsEqual(orderId, nil)) {
        
                    response:= (<-this.KalshiPrivateDeletePortfolioEventsOrdersOrderId(this.Extend(map[string]any {
            "order_id": orderId,
        }, params)))
                    ccxt.PanicOnError(response)
                    ccxt.AppendToArray(&canceledOrders, this.SafeDict(response, "order", response))
                }
            }
        
            ch <- this.ParseOrders(canceledOrders)
            return nil
        
            }()
            return ch
        }
/**
 * @method
 * @name kalshi#fetchEvents
 * @description fetches kalshi events via cursor-paginated /events, filters client-side by query strings, then fetches full event details with nested markets in parallel and caches in this.events
 * @see https://trading-api.readme.io/reference/getevents
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @param {string} [params.query] a single query string to filter events by (matches event ticker/title)
 * @param {string[]} [params.queries] multiple query strings (alternative to query)
 * @param {string} [params.status] 'open' | 'closed' | 'settled', defaults to options.defaultEventStatus
 * @param {int} [params.limit] page size per request, defaults to 200
 * @param {int} [params.maxPages] maximum number of event pages to scan, defaults to 50
 * @returns {object[]} an array of event structures
 */
func  (this *KalshiCore) FetchEvents(optionalArgs ...any) <- chan any {
            ch := make(chan any)
            go func() any {
                defer close(ch)
                defer ccxt.ReturnPanicError(ch)
                    params := ccxt.GetArg(optionalArgs, 0, map[string]any {})
            _ = params
            this.RequireEventQuery(params)
            var queries any = this.ParseSearchQueries(params)
            params = this.Omit(params, []any{"query", "queries"})
            // map the unified status onto the kalshi event status (open / closed) so it is pushed server-side
            var requestedStatus any = this.SafeString(params, "status", this.SafeString(this.Options, "defaultEventStatus", "active"))
            var status any = "open"
            if ccxt.IsTrue(ccxt.IsTrue((ccxt.IsEqual(requestedStatus, "closed"))) || ccxt.IsTrue((ccxt.IsEqual(requestedStatus, "inactive")))) {
                status = "closed"
            }
            var pageLimit any = this.SafeInteger(params, "limit", this.SafeInteger(this.Options, "defaultFetchEventsLimit", 200))
            var maxPages any = this.SafeInteger(params, "maxPages", 50)
            var rest any = this.Omit(params, []any{"status", "limit", "maxPages", "sort", "searchIn", "eventId", "slug"})
            if !ccxt.IsTrue(this.Events) {
                this.Events = map[string]any {}
            }
            if !ccxt.IsTrue(this.Markets) {
                this.Markets = this.CreateSafeDictionary()
            }
            var lowerQueries any = []any{}
            for qi := 0; ccxt.IsLessThan(qi, ccxt.GetArrayLength(queries)); qi++ {
                ccxt.AppendToArray(&lowerQueries, ccxt.ToLower(ccxt.GetValue(queries, qi)))
            }
            var lowerQueriesLength any =     ccxt.GetArrayLength(lowerQueries)
            // sequential cursor scan over events ONLY (no nested markets): a nested page is ~2.6 MB
            // (200 events + ~1200 markets), so scanning every open event that way transfers tens of MB
            // and takes ~100s. Event-only pages are ~25x smaller; the few events that match the query
            // then fetch their markets individually below (the per-event fallback). Net: seconds, not minutes.
            var matchedEvents any = []any{}
            var cursor any = nil
            var page any = 0
            for ccxt.IsLessThan(page, maxPages) {
                var request any = map[string]any {
                    "status": status,
                    "limit": pageLimit,
                    "with_nested_markets": false,
                }
                if ccxt.IsTrue(cursor) {
                    ccxt.AddElementToObject(request, "cursor", cursor)
                }
        
                response:= (<-this.KalshiPublicGetEvents(this.Extend(request, rest)))
                ccxt.PanicOnError(response)
                var rawEvents any = this.SafeList(response, "events", []any{})
                var rawEventsLength any =         ccxt.GetArrayLength(rawEvents)
                cursor = this.SafeString(response, "cursor")
                for rei := 0; ccxt.IsLessThan(rei, ccxt.GetArrayLength(rawEvents)); rei++ {
                    var rawEvent any = ccxt.GetValue(rawEvents, rei)
                    var ticker any = this.SafeString(rawEvent, "event_ticker", "")
                    var tickerLower any = ccxt.ToLower(ticker)
                    var title any = ccxt.ToLower(this.SafeString(rawEvent, "title", ""))
                    var matches any =             (ccxt.IsEqual(lowerQueriesLength, 0))
                    for li := 0; ccxt.IsLessThan(li, ccxt.GetArrayLength(lowerQueries)); li++ {
                        if ccxt.IsTrue(ccxt.IsTrue(ccxt.IsGreaterThan(ccxt.GetIndexOf(tickerLower, ccxt.GetValue(lowerQueries, li)), ccxt.OpNeg(1))) || ccxt.IsTrue(ccxt.IsGreaterThan(ccxt.GetIndexOf(title, ccxt.GetValue(lowerQueries, li)), ccxt.OpNeg(1)))) {
                            matches = true
                            break
                        }
                    }
                    if ccxt.IsTrue(ccxt.IsTrue(matches) && ccxt.IsTrue(ticker)) {
                        ccxt.AppendToArray(&matchedEvents, rawEvent)
                    }
                }
                page = this.Sum(page, 1)
                if ccxt.IsTrue(!ccxt.IsTrue(cursor) || ccxt.IsTrue(ccxt.IsLessThan(rawEventsLength, pageLimit))) {
                    break
                }
            }
            var result any = []any{}
            for di := 0; ccxt.IsLessThan(di, ccxt.GetArrayLength(matchedEvents)); di++ {
                var fullEvent any = ccxt.GetValue(matchedEvents, di)
                var rawNestedMarkets any = this.SafeList(fullEvent, "markets", []any{})
                var rawNestedMarketsLength any =         ccxt.GetArrayLength(rawNestedMarkets)
                if ccxt.IsTrue(ccxt.IsEqual(rawNestedMarketsLength, 0)) {
                    var eventTicker any = this.SafeString(fullEvent, "event_ticker")
                    if ccxt.IsTrue(!ccxt.IsEqual(eventTicker, nil)) {
                        var eventMarkets any = []any{}
                        var marketCursor any = nil
                        var marketsLimit any = this.SafeInteger(this.Options, "maxFetchMarketsLimit", 1000)
                        var maxMarketPages any = this.SafeInteger(this.Options, "maxMarketPages", 1000)
                        for mp := 0; ccxt.IsLessThan(mp, maxMarketPages); mp++ {
                            var marketRequest any = map[string]any {
                                "event_ticker": eventTicker,
                                "limit": marketsLimit,
                            }
                            if ccxt.IsTrue(!ccxt.IsEqual(marketCursor, nil)) {
                                ccxt.AddElementToObject(marketRequest, "cursor", marketCursor)
                            }
        
                            marketResponse:= (<-this.KalshiPublicGetMarkets(marketRequest))
                            ccxt.PanicOnError(marketResponse)
                            var pageMarkets any = this.SafeList(marketResponse, "markets", []any{})
                            var pageMarketsLength any =                     ccxt.GetArrayLength(pageMarkets)
                            for mi := 0; ccxt.IsLessThan(mi, ccxt.GetArrayLength(pageMarkets)); mi++ {
                                ccxt.AppendToArray(&eventMarkets, ccxt.GetValue(pageMarkets, mi))
                            }
                            marketCursor = this.SafeString(marketResponse, "cursor")
                            if ccxt.IsTrue(ccxt.IsTrue(ccxt.IsTrue((ccxt.IsEqual(marketCursor, nil))) || ccxt.IsTrue((ccxt.IsEqual(marketCursor, "")))) || ccxt.IsTrue((ccxt.IsLessThan(pageMarketsLength, marketsLimit)))) {
                                break
                            }
                        }
                        ccxt.AddElementToObject(fullEvent, "markets", eventMarkets)
                    }
                }
                var parsedEvent any = this.ParseEvent(fullEvent)
                var eventTitle any = this.SafeString(fullEvent, "title")
                var eventKey any = ccxt.Ternary(ccxt.IsTrue(eventTitle), this.ShortenSlug(eventTitle), nil)
                if ccxt.IsTrue(eventKey) {
                    ccxt.AddElementToObject(this.Events, eventKey, parsedEvent)
                    ccxt.AppendToArray(&result, parsedEvent)
                    var parsedMarketsRaw any = ccxt.GetValue(parsedEvent, "markets")
                    var parsedMarkets any = ccxt.Ternary(ccxt.IsTrue((!ccxt.IsEqual(parsedMarketsRaw, nil))), parsedMarketsRaw, []any{})
                    for mi := 0; ccxt.IsLessThan(mi, ccxt.GetArrayLength(parsedMarkets)); mi++ {
                        var m any = ccxt.GetValue(parsedMarkets, mi)
                        ccxt.AddElementToObject(this.Markets, ccxt.GetValue(m, "symbol"), m)
                    }
                }
            }
            this.Outcomes = map[string]any {}
            this.Outcomes_by_id = map[string]any {}
            var marketKeys any = ccxt.ObjectKeys(this.Markets)
            for i := 0; ccxt.IsLessThan(i, ccxt.GetArrayLength(marketKeys)); i++ {
                var market any = ccxt.GetValue(this.Markets, ccxt.GetValue(marketKeys, i))
                var outcomesList any = this.SafeList(market, "outcomes", []any{})
                for j := 0; ccxt.IsLessThan(j, ccxt.GetArrayLength(outcomesList)); j++ {
                    var oc any = ccxt.GetValue(outcomesList, j)
                    var ocSymbol any = this.SafeString(oc, "outcome")
                    if ccxt.IsTrue(!ccxt.IsEqual(ocSymbol, nil)) {
                        ccxt.AddElementToObject(this.Outcomes, ocSymbol, oc)
                    }
                    var ocId any = this.SafeString(oc, "outcomeId")
                    if ccxt.IsTrue(!ccxt.IsEqual(ocId, nil)) {
                        ccxt.AddElementToObject(this.Outcomes_by_id, ocId, oc)
                    }
                }
            }
        
            ch <- this.ApplyEventFetchParams(result, params, queries)
            return nil
        
            }()
            return ch
        }
/**
 * @method
 * @name kalshi#fetchEvent
 * @description fetches a single prediction-market event by its event ticker
 * @see https://trading-api.readme.io/reference/getevent
 * @param {string} id the event ticker
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {object} a [prediction event structure](https://docs.ccxt.com/#/?id=prediction-event-structure)
 */
func  (this *KalshiCore) FetchEvent(id any, optionalArgs ...any) <- chan any {
            ch := make(chan any)
            go func() any {
                defer close(ch)
                defer ccxt.ReturnPanicError(ch)
                    params := ccxt.GetArg(optionalArgs, 0, map[string]any {})
            _ = params
            var request any = map[string]any {
                "event_ticker": id,
                "with_nested_markets": true,
            }
        
            response:= (<-this.KalshiPublicGetEventsEventTicker(this.Extend(request, params)))
            ccxt.PanicOnError(response)
            var fullEvent any = this.SafeDict(response, "event", response)
            var nestedMarkets any = this.SafeList(fullEvent, "markets")
            if ccxt.IsTrue(ccxt.IsEqual(nestedMarkets, nil)) {
                ccxt.AddElementToObject(fullEvent, "markets", this.SafeList(response, "markets", []any{}))
            }
            var event any = this.ParseEvent(fullEvent)
        
            ch <- event
            return nil
        
            }()
            return ch
        }
/**
 * @ignore
 * @method
 * @name kalshi#parseEvent
 * @description parses a raw kalshi event object (with nested markets) into the unified CCXT event shape
 * @param {object} rawEvent the raw event object
 * @returns {object} an event structure
 */
func  (this *KalshiCore) ParseEvent(rawEvent any) any  {
    // {
    //         "available_on_brokers": true,
    //         "category": "Politics",
    //         "collateral_return_type": "",
    //         "event_ticker": "KXBALANCE-29",
    //         "last_updated_ts": "0001-01-01T00:00:00Z",
    //         "markets": [
    //             {
    //                 "can_close_early": true,
    //                 "close_time": "2029-07-01T14:00:00Z",
    //                 "created_time": "0001-01-01T00:00:00Z",
    //                 "early_close_condition": "This market will close and expire early if the event occurs.",
    //                 "event_ticker": "KXBALANCE-29",
    //                 "expected_expiration_time": "2029-07-01T14:00:00Z",
    //                 "expiration_time": "2029-07-01T14:00:00Z",
    //                 "expiration_value": "",
    //                 "fractional_trading_enabled": false,
    //                 "last_price_dollars": "0.1000",
    //                 "latest_expiration_time": "2029-07-01T14:00:00Z",
    //                 "liquidity_dollars": "0.0000",
    //                 "market_type": "binary",
    //                 "no_ask_dollars": "0.9000",
    //                 "no_bid_dollars": "0.8900",
    //                 "no_sub_title": "During Trump's term",
    //                 "notional_value_dollars": "1.0000",
    //                 "open_interest_fp": "16268.00",
    //                 "open_time": "2025-01-03T15:00:00Z",
    //                 "previous_price_dollars": "0.0000",
    //                 "previous_yes_ask_dollars": "0.0000",
    //                 "previous_yes_bid_dollars": "0.0000",
    //                 "price_level_structure": "linear_cent",
    //                 "price_ranges": [
    //                     {
    //                         "end": "1.0000",
    //                         "start": "0.0000",
    //                         "step": "0.0100"
    //                     }
    //                 ],
    //                 "response_price_units": "usd_cent",
    //                 "result": "",
    //                 "rules_primary": "If there is not a budget deficit for any of fiscal years 2025, 2026, 2027, or 2028, then the market resolves to Yes.",
    //                 "rules_secondary": "",
    //                 "settlement_timer_seconds": "1800",
    //                 "status": "active",
    //                 "subtitle": "",
    //                 "tick_size": "1",
    //                 "ticker": "KXBALANCE-29",
    //                 "title": "Will Trump balance the budget?",
    //                 "updated_time": "0001-01-01T00:00:00Z",
    //                 "volume_24h_fp": "28.00",
    //                 "volume_fp": "40111.00",
    //                 "yes_ask_dollars": "0.1100",
    //                 "yes_ask_size_fp": "",
    //                 "yes_bid_dollars": "0.1000",
    //                 "yes_bid_size_fp": "",
    //                 "yes_sub_title": "During Trump's term"
    //             }
    //         ],
    //         "mutually_exclusive": false,
    //         "series_ticker": "KXBALANCE",
    //         "strike_period": "",
    //         "sub_title": "During Trump's term",
    //         "title": "Will Trump balance the budget?"
    // }
    var rawMarkets any = this.SafeList(rawEvent, "markets", []any{})
    var marketsList any = []any{}
    // aggregate volume/liquidity from the markets and derive the creation time so sort works
    var totalVolume any = 0
    var totalLiquidity any = 0
    var earliestCreated any = nil
    for i := 0; ccxt.IsLessThan(i, ccxt.GetArrayLength(rawMarkets)); i++ {
        var rawMarket any = ccxt.GetValue(rawMarkets, i)
        var parsed any = this.ParseMarket(rawMarket)
        ccxt.AppendToArray(&marketsList, parsed)
        totalVolume = this.Sum(totalVolume, this.SafeNumber2(rawMarket, "volume_fp", "volume", 0))
        totalLiquidity = this.Sum(totalLiquidity, this.SafeNumber2(rawMarket, "liquidity_dollars", "liquidity", 0))
        var marketCreated any = this.Parse8601(this.SafeString(rawMarket, "open_time"))
        if ccxt.IsTrue(ccxt.IsTrue((!ccxt.IsEqual(marketCreated, nil))) && ccxt.IsTrue((ccxt.IsTrue((ccxt.IsEqual(earliestCreated, nil))) || ccxt.IsTrue((ccxt.IsLessThan(marketCreated, earliestCreated)))))) {
            earliestCreated = marketCreated
        }
    }
    var ticker any = this.SafeString(rawEvent, "event_ticker")
    var title any = this.SafeString(rawEvent, "title")
    var created any = this.Parse8601(this.SafeString(rawEvent, "created_date_iso"))
    if ccxt.IsTrue(ccxt.IsEqual(created, nil)) {
        created = earliestCreated
    }
    return this.Extend(map[string]any {
        "id": ticker,
        "slug": ticker,
        "event": ccxt.Ternary(ccxt.IsTrue(title), this.ShortenSlug(title), nil),
        "title": title,
        "markets": marketsList,
        "volume": totalVolume,
        "liquidity": totalLiquidity,
        "url": this.SafeString(rawEvent, "url"),
        "image": this.SafeString(rawEvent, "image_url"),
        "created": created,
        "createdDatetime": this.SafeString(rawEvent, "created_date_iso"),
        "end": this.Parse8601(this.SafeString(rawEvent, "end_date_iso")),
        "endDatetime": this.SafeString(rawEvent, "end_date_iso"),
        "category": this.SafeString(rawEvent, "category"),
        "lastUpdatedAt": this.Parse8601(this.SafeString(rawEvent, "last_updated_date_iso")),
        "lastUpdatedAtDatetime": this.SafeString(rawEvent, "last_updated_date_iso"),
        "resolutionSource": this.SafeString(rawEvent, "resolution_source"),
        "resolved": this.SafeBool(rawEvent, "resolved"),
        "info": rawEvent,
    })
}
/**
 * @ignore
 * @method
 * @name kalshi#sign
 * @description builds the request URL and attaches RSA-PSS SHA-256 authentication headers for private endpoints
 * @param {string} path the endpoint path
 * @param {string|string[]} [api] the api group and access level
 * @param {string} [method] HTTP method
 * @param {object} [params] request parameters
 * @param {object} [headers] request headers
 * @param {object} [body] request body
 * @returns {object} a dictionary with url, method, body and headers
 */
func  (this *KalshiCore) Sign(path any, optionalArgs ...any) any  {
    api := ccxt.GetArg(optionalArgs, 0, "kalshi")
    _ = api
    method := ccxt.GetArg(optionalArgs, 1, "GET")
    _ = method
    params := ccxt.GetArg(optionalArgs, 2, map[string]any {})
    _ = params
    headers := ccxt.GetArg(optionalArgs, 3, nil)
    _ = headers
    body := ccxt.GetArg(optionalArgs, 4, nil)
    _ = body
    var apiGroup any = ccxt.Ternary(ccxt.IsTrue(ccxt.IsString(api)), api, ccxt.GetValue(api, 0))
    var access any = ccxt.Ternary(ccxt.IsTrue(ccxt.IsString(api)), "public", ccxt.GetValue(api, 1))
    var baseUrls any = ccxt.GetValue(this.Urls, "api")
    var baseUrl any = this.SafeString(baseUrls, apiGroup, ccxt.GetValue(baseUrls, "kalshi"))
    var implodedPath any = this.ImplodeParams(path, params)
    var url any = ccxt.Add(ccxt.Add(baseUrl, "/"), implodedPath)
    var query any = this.Omit(params, this.ExtractParams(path))
    var querystring any = this.Urlencode(query)
    if ccxt.IsTrue(ccxt.IsTrue(ccxt.IsEqual(method, "GET")) && ccxt.IsTrue(querystring)) {
        url = ccxt.Add(url, ccxt.Add("?", querystring))
    }
    var existingHeaders any = ccxt.Ternary(ccxt.IsTrue((!ccxt.IsEqual(headers, nil))), headers, map[string]any {})
    headers = this.Extend(map[string]any {
        "Accept": "application/json",
        "Content-Type": "application/json",
    }, existingHeaders)
    if ccxt.IsTrue(ccxt.IsEqual(access, "private")) {
        this.CheckRequiredCredentials()
        var timestamp any = ccxt.ToString(this.Milliseconds())
        // Signing payload: {timestamp}{METHOD}{path}, where path is the full request path
        // INCLUDING the /trade-api/v2 prefix and any path params substituted in, but NOT
        // the query string (e.g. /trade-api/v2/portfolio/orders/{order_id})
        var tradeApiIndex any = ccxt.GetIndexOf(baseUrl, "/trade-api")
        var versionPrefix any = ccxt.Slice(baseUrl, tradeApiIndex, nil)
        var pathForSigning any = ccxt.Add(ccxt.Add(versionPrefix, "/"), implodedPath)
        var payload any = ccxt.Add(ccxt.Add(timestamp, method), pathForSigning)
        // RSA-PSS SHA-256 signature with the private key PEM
        var keyParts any = ccxt.Split(this.PrivateKey, "\n")
        var cleanPrivateKey any = ccxt.Join(keyParts, "\n")
        var signature any = ccxt.Rsa(payload, cleanPrivateKey, ccxt.Sha256, "pss")
        headers = this.Extend(headers, map[string]any {
            "KALSHI-ACCESS-KEY": this.ApiKey,
            "KALSHI-ACCESS-SIGNATURE": signature,
            "KALSHI-ACCESS-TIMESTAMP": timestamp,
        })
        if ccxt.IsTrue(ccxt.IsTrue(!ccxt.IsEqual(method, "GET")) && ccxt.IsTrue(querystring)) {
            // kalshi expects a JSON body; the signature covers only timestamp+method+path
            body = this.Json(query)
        }
    }
    return map[string]any {
        "url": url,
        "method": method,
        "body": body,
        "headers": headers,
    }
}


func (this *KalshiCore) Init(userConfig map[string]any) {
    this.Exchange = ccxt.Exchange{}
    this.Exchange.DerivedExchange = this
    this.Exchange.InitParent(userConfig, this.Describe().(map[string]any), this)
}
